  missing_landmark_locations integer;
  missing_complex_locations integer;
  missing_listing_normalized integer;
  missing_landmark_normalized integer;
  missing_thumbnail_count integer;
  stay_count integer;
  exp_count integer;
  svc_count integer;
  featured_landmark_count integer;
  province_without_all_categories integer;
BEGIN
  SELECT COUNT(*) INTO missing_listing_locations FROM public.listings WHERE latitude IS NOT NULL AND longitude IS NOT NULL AND location IS NULL;
  SELECT COUNT(*) INTO missing_landmark_locations FROM public.landmarks WHERE latitude IS NOT NULL AND longitude IS NOT NULL AND location IS NULL;
  SELECT COUNT(*) INTO missing_complex_locations FROM public.complexes WHERE latitude IS NOT NULL AND longitude IS NOT NULL AND location IS NULL;
  IF missing_listing_locations > 0 OR missing_landmark_locations > 0 OR missing_complex_locations > 0 THEN
    RAISE EXCEPTION 'Seed verification failed: missing locations listings=%, landmarks=%, complexes=%', missing_listing_locations, missing_landmark_locations, missing_complex_locations;
  END IF;
  SELECT COUNT(*) INTO missing_listing_normalized FROM public.listings WHERE status = 'ACTIVE' AND title IS NOT NULL AND title_normalized IS NULL;
  SELECT COUNT(*) INTO missing_landmark_normalized FROM public.landmarks WHERE status = 'ACTIVE' AND name IS NOT NULL AND name_normalized IS NULL;
  IF missing_listing_normalized > 0 OR missing_landmark_normalized > 0 THEN
    RAISE EXCEPTION 'Seed verification failed: missing normalized text listings=%, landmarks=%', missing_listing_normalized, missing_landmark_normalized;
  END IF;
  SELECT COUNT(*) INTO missing_thumbnail_count FROM public.listings WHERE status = 'ACTIVE' AND (thumbnail_url IS NULL OR thumbnail_url = '');
  IF missing_thumbnail_count > 0 THEN
    RAISE EXCEPTION 'Seed verification failed: % active listings missing thumbnail', missing_thumbnail_count;
  END IF;
  SELECT COUNT(*) INTO stay_count FROM public.listings WHERE status = 'ACTIVE' AND category = 'STAY';
  SELECT COUNT(*) INTO exp_count FROM public.listings WHERE status = 'ACTIVE' AND category = 'EXP';
  SELECT COUNT(*) INTO svc_count FROM public.listings WHERE status = 'ACTIVE' AND category = 'SVC';
  IF stay_count < 100 OR exp_count < 60 OR svc_count < 50 THEN
    RAISE EXCEPTION 'Seed verification failed: category counts STAY=%, EXP=%, SVC=%', stay_count, exp_count, svc_count;
  END IF;
  SELECT COUNT(*) INTO featured_landmark_count FROM public.landmarks WHERE status = 'ACTIVE' AND is_featured = true;
  IF featured_landmark_count < 6 THEN
    RAISE EXCEPTION 'Seed verification failed: only % featured landmarks', featured_landmark_count;
  END IF;
  WITH active_provinces AS (
    SELECT DISTINCT province FROM public.landmarks WHERE status = 'ACTIVE' AND province IS NOT NULL
  ), province_category_counts AS (
    SELECT p.province, COUNT(DISTINCT l.category) AS category_count
    FROM active_provinces p
    LEFT JOIN public.listings l ON l.province = p.province AND l.status = 'ACTIVE'
    GROUP BY p.province
  )
  SELECT COUNT(*) INTO province_without_all_categories FROM province_category_counts WHERE category_count < 3;
  IF province_without_all_categories > 0 THEN
    RAISE EXCEPTION 'Seed verification failed: % provinces do not have all listing categories', province_without_all_categories;
  END IF;
  RAISE NOTICE 'Seed verification passed: STAY=%, EXP=%, SVC=%, featured landmarks=%', stay_count, exp_count, svc_count, featured_landmark_count;
END $$;
